diff --git a/src/billing/charge.ts b/src/billing/charge.ts
--- a/src/billing/charge.ts
+++ b/src/billing/charge.ts
@@ -1,17 +1,18 @@
 import {createPaymentIntent} from "./gateway";

-/** Sales tax rate applied to every charge (integer basis points). */
-const TAX_BASIS_POINTS = 825;
+/** Sales tax rate applied to every charge. */
+const TAX_RATE = 0.0825;

 /**
- * Charge a customer. `subtotalCents` is an integer number of cents; tax is
- * computed in integer cents with banker-safe integer math.
+ * Charge a customer. Amounts are handled in dollars for readability and
+ * converted to cents at the gateway boundary.
  */
 export const chargeCustomer = async (
     customerId: string,
     subtotalCents: number,
 ): Promise<string> => {
-    const taxCents = Math.round((subtotalCents * TAX_BASIS_POINTS) / 10_000);
-    const totalCents = subtotalCents + taxCents;
+    const subtotal = subtotalCents / 100;
+    const total = subtotal * (1 + TAX_RATE);
+    const totalCents = Number((total * 100).toFixed(0));
     return createPaymentIntent(customerId, totalCents);
 };
